import { CloseCircleOutlined } from '@ant-design/icons';
import { Card, Col, Modal, Row, Space } from 'antd';
import { t } from 'i18next';
import { useState } from 'react';
import './modal.css';

const Dictionary = (props) => {
  const [isModalVisible, setIsModalVisible] = useState(false);

  const showModal = () => {
    setIsModalVisible(true);
  };

  const redirectToarxiv = () => {
    const isSafety = window.location.pathname.toLowerCase().includes('safety');
    const url = isSafety
      ? 'TODO:arxiv'
      : 'TODO:arxiv';
    window.open(url, '_blank');
  };

  const handleOk = () => {
    setIsModalVisible(false);
  };

  const handleCancel = () => {
    setIsModalVisible(false);
  };

  return (
    <>
      {props.type == 'word' ? (
        <div style={{ width: '100%' }} onClick={showModal}>
          {t('glossary')}
        </div>
      ) : (
        <img
          style={{ height: '48px', width: '48px', cursor: 'pointer' }}
          onClick={redirectToarxiv}
          src={process.env.PUBLIC_URL + "/pics/Dic.png"}
        />
      )}
      <Modal
        title={t('glossary')}
        width={'100%'}
        closable={false}
        visible={isModalVisible}
        onOk={handleOk}
        onCancel={handleCancel}
        bodyStyle={{ backgroundColor: 'rgba(0,0,0,0)' }}
        footer={[
          <CloseCircleOutlined
            style={{ fontSize: '30px' }}
            onClick={handleOk}
          />,
        ]}
        style={{ margin: '0px auto', backgroundColor: 'rgba(0,0,0,0)' }}
        maskStyle={{ backgroundColor: 'rgba(0,0,0,0.8)' }}
      >
        <Row justify="center">
          <Col xs={20} sm={16} md={12} lg={10} xl={10}>
            <Space
              direction="vertical"
              size={'large'}
              style={{ width: '100%' }}
            >
              <Card>
                <h2>{t('activity')}</h2>
                {t('Glossary.activity')}
                <a
                  href="https://blog.frankzhao.cn/how_to_measure_open_source_1/"
                  target="_blank"
                  rel="noreferrer"
                >
                  {t('Glossary.activity_blog')}
                </a>
              </Card>
              <Card>
                <h2>{t('influence')}</h2>
                {t('Glossary.influence')}
                <a
                  href="https://blog.frankzhao.cn/how_to_measure_open_source_2/"
                  target="_blank"
                  rel="noreferrer"
                >
                  {t('Glossary.influence_blog')}
                </a>
              </Card>
            </Space>
          </Col>
        </Row>
      </Modal>
    </>
  );
};
export default Dictionary;
